MAST01: PROC OPTIONS(MAIN);
  DCL WS-MSG CHAR(60);
  DCL 1 DFHCOMMAREA,
        2 INPUT-DATA CHAR(100);

  IF EIBCALEN = 0 THEN DO;
    WS-MSG = 'ERROR: NO INPUT COMMAREA RECEIVED';
    EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
    EXEC CICS RETURN;
  END;

  WS-MSG = 'OK: INPUT RECEIVED';
  EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
  EXEC CICS RETURN;
END MAST01;
